const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne boit du café","image_prompt":"A person drinking coffee at a kitchen table, morning light"},{"id":"B","text":"Une personne prend le bus","image_prompt":"A person waiting at a bus stop in urban setting"},{"id":"C","text":"Une personne lit le journal","image_prompt":"A person reading a newspaper on a sofa"},{"id":"D","text":"Une personne cuisine le dîner","image_prompt":"A person cooking dinner in a modern kitchen"}],"correct":0,"transcript_fr":"Chaque matin, avant d'aller travailler, je prends toujours le temps de savourer une bonne tasse de café bien chaud.","transcript_en":"Every morning, before going to work, I always take the time to enjoy a good hot cup of coffee.","points":[{"point":1,"male_lines":["Chaque matin, avant d'aller travailler, je prends toujours le temps de savourer une bonne tasse de café bien chaud."]}]},{"id":2,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une voiture roule sur l'autoroute","image_prompt":"A car driving on a highway with mountains in background"},{"id":"B","text":"Un train arrive en gare","image_prompt":"A train arriving at a station platform"},{"id":"C","text":"Un avion décolle","image_prompt":"An airplane taking off from runway"},{"id":"D","text":"Un vélo est garé devant un magasin","image_prompt":"A bicycle parked in front of a store"}],"correct":1,"transcript_fr":"J'ai décidé de prendre le train pour Montréal cette fois-ci, c'est beaucoup plus relaxant que de conduire.","transcript_en":"I decided to take the train to Montreal this time, it's much more relaxing than driving.","points":[{"point":1,"male_lines":["J'ai décidé de prendre le train pour Montréal cette fois-ci, c'est beaucoup plus relaxant que de conduire."]}]},{"id":3,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Il neige abondamment","image_prompt":"Heavy snowfall covering city streets and trees"},{"id":"B","text":"Il pleut avec des nuages gris","image_prompt":"Rain falling from grey clouds over cityscape"},{"id":"C","text":"Il fait soleil et chaud","image_prompt":"Bright sunny day with clear blue sky"},{"id":"D","text":"Il y a du brouillard","image_prompt":"Thick fog covering a city bridge"}],"correct":2,"transcript_fr":"Quelle belle journée ensoleillée ! Il fait vraiment chaud pour un mois de mai.","transcript_en":"What a beautiful sunny day! It's really hot for the month of May.","points":[{"point":1,"male_lines":["Quelle belle journée ensoleillée ! Il fait vraiment chaud pour un mois de mai."]}]},{"id":4,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne achète des légumes au marché","image_prompt":"A person buying vegetables at an outdoor farmers market"},{"id":"B","text":"Une personne fait les courses au supermarché","image_prompt":"A person pushing a shopping cart in a supermarket aisle"},{"id":"C","text":"Une personne essaie des vêtements","image_prompt":"A person trying on clothes in a fitting room"},{"id":"D","text":"Une personne paie à la caisse","image_prompt":"A person paying at a checkout counter with cashier"}],"correct":0,"transcript_fr":"J'aime faire mes courses au marché fermier le samedi matin pour avoir des produits frais et locaux.","transcript_en":"I like to shop at the farmers market on Saturday mornings to get fresh and local products.","points":[{"point":1,"male_lines":["J'aime faire mes courses au marché fermier le samedi matin pour avoir des produits frais et locaux."]}]},{"id":5,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne travaille sur ordinateur","image_prompt":"A person working on a laptop at a desk"},{"id":"B","text":"Une personne participe à une réunion","image_prompt":"People sitting around a conference table in meeting"},{"id":"C","text":"Une personne parle au téléphone","image_prompt":"A person talking on phone in office setting"},{"id":"D","text":"Une personne présente un projet","image_prompt":"A person giving a presentation with charts on screen"}],"correct":3,"transcript_fr":"Aujourd'hui, je dois présenter mon projet devant toute l'équipe et les directeurs.","transcript_en":"Today, I have to present my project in front of the whole team and the directors.","points":[{"point":1,"male_lines":["Aujourd'hui, je dois présenter mon projet devant toute l'équipe et les directeurs."]}]},{"id":6,"section":"A","theme":"Leisure","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Des amis au cinéma","image_prompt":"Friends sitting in a movie theater watching film"},{"id":"B","text":"Une personne au musée","image_prompt":"A person looking at paintings in an art museum"},{"id":"C","text":"Des gens au concert","image_prompt":"People at a concert with stage lights"},{"id":"D","text":"Une personne à la bibliothèque","image_prompt":"A person reading books in a quiet library"}],"correct":2,"transcript_fr":"Nous avons des billets pour le concert de Céline Dion au Centre Bell ce soir, j'ai tellement hâte !","transcript_en":"We have tickets for Céline Dion's concert at the Bell Centre tonight, I can't wait!","points":[{"point":1,"male_lines":["Nous avons des billets pour le concert de Céline Dion au Centre Bell ce soir, j'ai tellement hâte !"]}]},{"id":7,"section":"B","theme":"Restaurant","question":"Où se déroule cette conversation ?","options":[{"id":"A","text":"Dans un hôtel","image_prompt":null},{"id":"B","text":"Dans un restaurant","image_prompt":null},{"id":"C","text":"Dans un magasin","image_prompt":null},{"id":"D","text":"Dans une banque","image_prompt":null}],"correct":1,"transcript_fr":"Bonjour, j'ai réservé une table pour deux personnes au nom de Tremblay. - Oui, bien sûr monsieur, suivez-moi par ici. Voici la carte, votre serveur arrive dans un instant.","transcript_en":"Hello, I reserved a table for two under the name Tremblay. - Yes, of course sir, follow me this way. Here is the menu, your server will be with you in a moment.","points":[{"point":1,"male_lines":["Bonjour, j'ai réservé une table pour deux personnes au nom de Tremblay."],"female_lines":["Oui, bien sûr monsieur, suivez-moi par ici. Voici la carte, votre serveur arrive dans un instant."]},{"point":2,"male_lines":["Merci beaucoup. Est-ce que vous avez des spécialités du jour à me recommander ?"],"female_lines":["Oui, notre chef propose un excellent saumon grillé avec des légumes de saison."]},{"point":3,"male_lines":["Ça a l'air délicieux. Je vais prendre ça comme plat principal."],"female_lines":["Parfait. Et comme boisson, qu'est-ce qui vous ferait plaisir ?"]},{"point":4,"male_lines":["Je vais prendre un verre de vin rouge, merci."],"female_lines":["Très bien, je note tout ça et je reviens tout de suite avec votre vin."]}]},{"id":8,"section":"B","theme":"Post office","question":"Que veut faire le client ?","options":[{"id":"A","text":"Envoyer un colis","image_prompt":null},{"id":"B","text":"Acheter des timbres","image_prompt":null},{"id":"C","text":"Retirer de l'argent","image_prompt":null},{"id":"D","text":"Ouvrir un compte","image_prompt":null}],"correct":0,"transcript_fr":"Bonjour madame, j'aimerais envoyer ce colis à Vancouver. - D'accord, est-ce que vous voulez l'envoyer par poste régulière ou express ?","transcript_en":"Hello madam, I would like to send this package to Vancouver. - Okay, would you like to send it by regular mail or express?","points":[{"point":1,"male_lines":["Bonjour madame, j'aimerais envoyer ce colis à Vancouver."],"female_lines":["D'accord, est-ce que vous voulez l'envoyer par poste régulière ou express ?"]},{"point":2,"male_lines":["Quelle est la différence de prix et de délai entre les deux options ?"],"female_lines":["L'express coûte quinze dollars et arrive demain, la régulière coûte huit dollars pour trois jours."]},{"point":3,"male_lines":["Je vais prendre l'express, c'est urgent. Le colis est-il bien emballé ainsi ?"],"female_lines":["Oui, l'emballage semble correct. Remplissez juste ce formulaire d'expédition."]},{"point":4,"male_lines":["Voilà, c'est rempli. Puis-je payer par carte de crédit ?"],"female_lines":["Bien sûr, passez votre carte ici. Voici votre reçu et le numéro de suivi."]}]},{"id":9,"section":"B","theme":"Doctor","question":"Quel est le problème du patient ?","options":[{"id":"A","text":"Il a mal à la tête","image_prompt":null},{"id":"B","text":"Il a mal au dos","image_prompt":null},{"id":"C","text":"Il a mal à la gorge","image_prompt":null},{"id":"D","text":"Il a mal au ventre","image_prompt":null}],"correct":2,"transcript_fr":"Docteur, j'ai vraiment mal à la gorge depuis trois jours et j'ai de la fièvre. - Je vais vous examiner. Ouvrez la bouche et dites 'aaaaah'.","transcript_en":"Doctor, I have a really sore throat for three days and I have a fever. - I'll examine you. Open your mouth and say 'aaaaah'.","points":[{"point":1,"male_lines":["Docteur, j'ai vraiment mal à la gorge depuis trois jours et j'ai de la fièvre."],"female_lines":["Je vais vous examiner. Ouvrez la bouche et dites 'aaaaah'."]},{"point":2,"male_lines":["Aaaaaah. J'ai aussi du mal à avaler depuis hier soir."],"female_lines":["Vos amygdales sont très enflammées. Vous avez probablement une angine."]},{"point":3,"male_lines":["Est-ce que c'est grave docteur ? J'ai un voyage prévu la semaine prochaine."],"female_lines":["Non, ce n'est pas grave, mais vous devez prendre des antibiotiques pendant une semaine."]},{"point":4,"male_lines":["D'accord, je vais suivre le traitement. Merci beaucoup docteur."],"female_lines":["Revenez me voir si les symptômes persistent après cinq jours. Bon rétablissement !"]}]},{"id":10,"section":"B","theme":"Bank","question":"Que demande le client ?","options":[{"id":"A","text":"Un prêt immobilier","image_prompt":null},{"id":"B","text":"Une carte de crédit","image_prompt":null},{"id":"C","text":"Un relevé de compte","image_prompt":null},{"id":"D","text":"De l'argent liquide","image_prompt":null}],"correct":1,"transcript_fr":"Bonjour, je voudrais demander une carte de crédit s'il vous plaît. - Très bien, avez-vous déjà un compte chez nous ?","transcript_en":"Hello, I would like to apply for a credit card please. - Very well, do you already have an account with us?","points":[{"point":1,"male_lines":["Bonjour, je voudrais demander une carte de crédit s'il vous plaît."],"female_lines":["Très bien, avez-vous déjà un compte chez nous ?"]},{"point":2,"male_lines":["Oui, j'ai un compte chèques depuis deux ans maintenant."],"female_lines":["Parfait. Je vais avoir besoin de votre pièce d'identité et d'un justificatif de revenus."]},{"point":3,"male_lines":["Voici ma carte d'assurance maladie et ma fiche de paie du mois dernier."],"female_lines":["Merci. Quelle limite de crédit souhaitez-vous pour cette carte ?"]},{"point":4,"male_lines":["Cinq mille dollars serait suffisant pour mes besoins. Quels sont les taux d'intérêt ?"],"female_lines":["Le taux est de dix-neuf virgule quatre pour cent. Votre carte sera prête dans cinq jours ouvrables."]}]},{"id":11,"section":"C","theme":"Airport announcement","question":"Quelle information est donnée dans cette annonce ?","options":[{"id":"A","text":"Un vol est retardé","image_prompt":null},{"id":"B","text":"Un vol est annulé","image_prompt":null},{"id":"C","text":"Un vol est en embarquement","image_prompt":null},{"id":"D","text":"Un vol est arrivé","image_prompt":null}],"correct":0,"transcript_fr":"Mesdames et messieurs, nous vous informons que le vol Air Canada trois-cinq-sept à destination de Calgary est retardé d'une heure en raison des conditions météorologiques. L'embarquement débutera à quatorze heures trente à la porte vingt-deux. Nous vous prions de bien vouloir nous excuser pour ce désagrément.","transcript_en":"Ladies and gentlemen, we inform you that Air Canada flight three-five-seven to Calgary is delayed by one hour due to weather conditions. Boarding will begin at two-thirty PM at gate twenty-two. We apologize for this inconvenience.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous vous informons que le vol Air Canada trois-cinq-sept à destination de Calgary est retardé d'une heure en raison des conditions météorologiques."],"female_lines":[]},{"point":2,"male_lines":["L'embarquement débutera à quatorze heures trente à la porte vingt-deux."],"female_lines":[]},{"point":3,"male_lines":["Nous vous prions de bien vouloir nous excuser pour ce désagrément."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Que demande l'annonce ?","options":[{"id":"A","text":"De venir à la caisse numéro 5","image_prompt":null},{"id":"B","text":"De retrouver un enfant perdu","image_prompt":null},{"id":"C","text":"De signaler un article en promotion","image_prompt":null},{"id":"D","text":"D'évacuer le magasin","image_prompt":null}],"correct":1,"transcript_fr":"Attention clients, nous recherchons les parents d'un petit garçon nommé Maxime, âgé de cinq ans, portant un manteau rouge et des bottes bleues. Il se trouve actuellement au service à la clientèle près des caisses. Merci de venir le récupérer rapidement.","transcript_en":"Attention customers, we are looking for the parents of a little boy named Maxime, five years old, wearing a red coat and blue boots. He is currently at the customer service desk near the cash registers. Please come pick him up quickly.","points":[{"point":1,"male_lines":["Attention clients, nous recherchons les parents d'un petit garçon nommé Maxime, âgé de cinq ans, portant un manteau rouge et des bottes bleues."],"female_lines":[]},{"point":2,"male_lines":["Il se trouve actuellement au service à la clientèle près des caisses."],"female_lines":[]},{"point":3,"male_lines":["Merci de venir le récupérer rapidement."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Train station announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"Le train part d'une autre voie","image_prompt":null},{"id":"B","text":"Le train est supprimé","image_prompt":null},{"id":"C","text":"Le train a du retard","image_prompt":null},{"id":"D","text":"Le train est complet","image_prompt":null}],"correct":0,"transcript_fr":"Voyageurs du train VIA Rail soixante-quinze en direction de Québec, veuillez noter que le départ se fera désormais sur la voie huit au lieu de la voie cinq. Nous vous invitons à vous diriger vers la nouvelle voie immédiatement. Le départ est maintenu à dix-huit heures quarante-cinq.","transcript_en":"Passengers of VIA Rail train seventy-five to Quebec, please note that departure will now be from track eight instead of track five. We invite you to proceed to the new track immediately. Departure is maintained at six forty-five PM.","points":[{"point":1,"male_lines":["Voyageurs du train VIA Rail soixante-quinze en direction de Québec, veuillez noter que le départ se fera désormais sur la voie huit au lieu de la voie cinq."],"female_lines":[]},{"point":2,"male_lines":["Nous vous invitons à vous diriger vers la nouvelle voie immédiatement."],"female_lines":[]},{"point":3,"male_lines":["Le départ est maintenu à dix-huit heures quarante-cinq."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Museum announcement","question":"Quelle information contient cette annonce ?","options":[{"id":"A","text":"Le musée ferme dans une heure","image_prompt":null},{"id":"B","text":"Une exposition est temporairement fermée","image_prompt":null},{"id":"C","text":"Un guide est disponible pour une visite","image_prompt":null},{"id":"D","text":"Le restaurant du musée est complet","image_prompt":null}],"correct":2,"transcript_fr":"Chers visiteurs, nous vous rappelons qu'une visite guidée de l'exposition sur les peintres impressionnistes commence dans dix minutes au hall principal. Notre guide Marie sera ravie de vous faire découvrir les chefs-d'œuvre de Monet et Renoir. L'activité est incluse dans le prix d'entrée.","transcript_en":"Dear visitors, we remind you that a guided tour of the Impressionist painters exhibition begins in ten minutes in the main hall. Our guide Marie will be delighted to show you the masterpieces of Monet and Renoir. The activity is included in the admission price.","points":[{"point":1,"male_lines":["Chers visiteurs, nous vous rappelons qu'une visite guidée de l'exposition sur les peintres impressionnistes commence dans dix minutes au hall principal."],"female_lines":[]},{"point":2,"male_lines":["Notre guide Marie sera ravie de vous faire découvrir les chefs-d'œuvre de Monet et Renoir."],"female_lines":[]},{"point":3,"male_lines":["L'activité est incluse dans le prix d'entrée."],"female_lines":[]}]},{"id":15,"section":"C","theme":"University announcement","question":"Que doit faire l'étudiant selon cette annonce ?","options":[{"id":"A","text":"S'inscrire aux cours avant vendredi","image_prompt":null},{"id":"B","text":"Payer les frais de scolarité","image_prompt":null},{"id":"C","text":"Récupérer sa carte étudiante","image_prompt":null},{"id":"D","text":"Choisir ses options de cours","image_prompt":null}],"correct":0,"transcript_fr":"Étudiants de première année, attention : la période d'inscription aux cours du semestre d'hiver se termine ce vendredi à seize heures. Passé ce délai, des frais de retard de cinquante dollars seront appliqués. Rendez-vous sur le portail étudiant pour finaliser votre choix de cours.","transcript_en":"First-year students, attention: the course registration period for the winter semester ends this Friday at four PM. After this deadline, a fifty-dollar late fee will be applied. Go to the student portal to finalize your course selection.","points":[{"point":1,"male_lines":["Étudiants de première année, attention : la période d'inscription aux cours du semestre d'hiver se termine ce vendredi à seize heures."],"female_lines":[]},{"point":2,"male_lines":["Passé ce délai, des frais de retard de cinquante dollars seront appliqués."],"female_lines":[]},{"point":3,"male_lines":["Rendez-vous sur le portail étudiant pour finaliser votre choix de cours."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Public transport announcement","question":"Quel problème est signalé ?","options":[{"id":"A","text":"Une grève des conducteurs","image_prompt":null},{"id":"B","text":"Des travaux sur la ligne","image_prompt":null},{"id":"C","text":"Une panne de signalisation","image_prompt":null},{"id":"D","text":"Un accident sur les voies","image_prompt":null}],"correct":1,"transcript_fr":"Usagers du métro, la ligne verte est interrompue entre les stations Lionel-Groulx et Atwater jusqu'à dix-sept heures en raison de travaux de maintenance. Un service de bus navette est mis en place. Nous vous recommandons de prévoir davantage de temps pour votre trajet.","transcript_en":"Metro users, the green line is interrupted between Lionel-Groulx and Atwater stations until five PM due to maintenance work. A shuttle bus service is in place. We recommend allowing more time for your journey.","points":[{"point":1,"male_lines":["Usagers du métro, la ligne verte est interrompue entre les stations Lionel-Groulx et Atwater jusqu'à dix-sept heures en raison de travaux de maintenance."],"female_lines":[]},{"point":2,"male_lines":["Un service de bus navette est mis en place."],"female_lines":[]},{"point":3,"male_lines":["Nous vous recommandons de prévoir davantage de temps pour votre trajet."],"female_lines":[]}]},{"id":17,"section":"D","theme":"Job interview","question":"Quelle est l'intention du candidat ?","options":[{"id":"A","text":"Demander une augmentation","image_prompt":null},{"id":"B","text":"Obtenir des informations sur le poste","image_prompt":null},{"id":"C","text":"Se plaindre de son ancien emploi","image_prompt":null},{"id":"D","text":"Refuser l'offre d'emploi","image_prompt":null}],"correct":1,"transcript_fr":"Pourriez-vous me donner plus de détails sur les responsabilités de ce poste ? - Bien sûr. Vous seriez responsable de la gestion de l'équipe de vente et du développement des nouveaux clients.","transcript_en":"Could you give me more details about the responsibilities of this position? - Of course. You would be responsible for managing the sales team and developing new clients.","points":[{"point":1,"male_lines":["Bonjour madame, merci de me recevoir pour cet entretien."],"female_lines":["Bonjour monsieur, je vous en prie. Asseyez-vous donc."]},{"point":2,"male_lines":["Pourriez-vous me donner plus de détails sur les responsabilités de ce poste ?"],"female_lines":["Bien sûr. Vous seriez responsable de la gestion de l'équipe de vente et du développement des nouveaux clients."]},{"point":3,"male_lines":["Et concernant les horaires de travail, y a-t-il de la flexibilité ?"],"female_lines":["Nous proposons du télétravail deux jours par semaine et les horaires sont relativement flexibles."]},{"point":4,"male_lines":["Cela me convient parfaitement. Quand pourrai-je espérer une réponse de votre part ?"],"female_lines":["Nous vous contacterons d'ici la fin de la semaine prochaine. Merci pour votre venue."]}]},{"id":18,"section":"D","theme":"Neighbor complaint","question":"Que veut faire la locataire ?","options":[{"id":"A","text":"Déménager","image_prompt":null},{"id":"B","text":"Se plaindre du bruit","image_prompt":null},{"id":"C","text":"Demander une réparation","image_prompt":null},{"id":"D","text":"Inviter son voisin","image_prompt":null}],"correct":1,"transcript_fr":"Excusez-moi monsieur, mais vos soirées très bruyantes m'empêchent de dormir. - Oh, je suis désolé, je ne pensais pas que cela vous dérangeait autant.","transcript_en":"Excuse me sir, but your very noisy parties are preventing me from sleeping. - Oh, I'm sorry, I didn't think it bothered you that much.","points":[{"point":1,"male_lines":["Bonjour madame, puis-je vous aider ?"],"female_lines":["Bonjour monsieur. Excusez-moi de vous déranger, mais j'aimerais vous parler d'un problème."]},{"point":2,"male_lines":["De quel problème s'agit-il ?"],"female_lines":["Vos soirées très bruyantes le week-end m'empêchent de dormir et je travaille tôt le lendemain."]},{"point":3,"male_lines":["Oh, je suis vraiment désolé, je ne pensais pas que le bruit portait autant."],"female_lines":["Je comprends que vous vouliez vous amuser, mais pourriez-vous baisser le volume après vingt-deux heures ?"]},{"point":4,"male_lines":["Bien sûr, je ferai attention à l'avenir. Encore mes excuses pour le dérangement."],"female_lines":["Je vous remercie de votre compréhension. Bonne journée monsieur."]}]},{"id":19,"section":"D","theme":"Return item","question":"Quel est l'objectif du client ?","options":[{"id":"A","text":"Échanger un article défectueux","image_prompt":null},{"id":"B","text":"Obtenir un remboursement","image_prompt":null},{"id":"C","text":"Acheter un accessoire","imageimage_prompt":null},{"id":"D","text":"Prendre un rendez-vous","image_prompt":null}],"correct":0,"transcript_fr":"J'aimerais échanger ce téléphone car il ne charge plus correctement. - Pas de problème, avez-vous le reçu et la boîte d'origine ?","transcript_en":"I would like to exchange this phone because it no longer charges properly. - No problem, do you have the receipt and the original box?","points":[{"point":1,"male_lines":["Bonjour, j'aimerais échanger ce téléphone que j'ai acheté la semaine dernière."],"female_lines":["Bonjour monsieur. Quel est le problème avec l'appareil ?"]},{"point":2,"male_lines":["Il ne charge plus correctement et la batterie se décharge en quelques heures seulement."],"female_lines":["Je vois. Avez-vous le reçu et la boîte d'origine avec tous les accessoires ?"]},{"point":3,"male_lines":["Oui, tout est là. J'espérais pouvoir prendre le même modèle mais qui fonctionne cette fois."],"female_lines":["Bien sûr, je vais vérifier si nous en avons en stock. Un instant s'il vous plaît."]},{"point":4,"male_lines":["Parfait, je vous remercie. Est-ce que la garantie couvre aussi le nouveau téléphone ?"],"female_lines":["Oui, la garantie est transférée sur l'appareil de remplacement. Voici votre nouveau téléphone."]}]},{"id":20,"section":"D","theme":"Making invitation","question":"Que propose la femme ?","options":[{"id":"A","text":"Dîner au restaurant","image_prompt":null},{"id":"B","text":"Aller au cinéma","image_prompt":null},{"id":"C","text":"Venir chez elle","image_prompt":null},{"id":"D","text":"Faire une randonnée","image_prompt":null}],"correct":2,"transcript_fr":"Si vous voulez, vous pouvez passer chez moi samedi soir pour regarder le match. - C'est gentil, j'accepte avec plaisir !","transcript_en":"If you want, you can come over to my place Saturday evening to watch the game. - That's nice, I accept with pleasure!","points":[{"point":1,"male_lines":["Allo Marie ? C'est Pierre. Tu fais quoi samedi soir ?"],"female_lines":["Salut Pierre ! Je n'ai rien de prévu pour l'instant. Pourquoi ?"]},{"point":2,"male_lines":["Il y a le match des Canadiens et je me demandais si tu voulais le regarder ensemble."],"female_lines":["Ah oui, bonne idée ! Si tu veux, tu peux passer chez moi, j'ai le grand écran."]},{"point":3,"male_lines":["C'est gentil de proposer. Je peux amener quelque chose à manger ?"],"female_lines":["Tu peux prendre des chips et des boissons si ça te dit, je préparerai des sandwiches."]},{"point":4,"male_lines":["Parfait, je passe vers dix-neuf heures alors. À samedi !"],"female_lines":["À samedi Pierre, ça va être sympa !"]}]},{"id":21,"section":"D","theme":"Asking for help","question":"Quelle aide demande l'homme ?","options":[{"id":"A","text":"De l'aide pour déménager","image_prompt":null},{"id":"B","text":"De l'aide pour réparer sa voiture","image_prompt":null},{"id":"C","text":"De l'aide pour un travail informatique","image_prompt":null},{"id":"D","text":"De l'aide pour cuisiner","image_prompt":null}],"correct":2,"transcript_fr":"Tu pourrais m'aider à configurer mon nouveau logiciel ? Je n'y comprends rien. - Oui, passe ce soir, je te montrerai comment faire.","transcript_en":"Could you help me set up my new software? I don't understand anything about it. - Yes, come over tonight, I'll show you how to do it.","points":[{"point":1,"male_lines":["Salut Sophie, tu as cinq minutes ? J'ai un problème avec mon ordinateur."],"female_lines":["Oui, bien sûr. Qu'est-ce qui se passe ?"]},{"point":2,"male_lines":["J'ai installé un nouveau logiciel mais je n'arrive pas à le configurer correctement."],"female_lines":["Quel logiciel est-ce ? Je connais peut-être."]},{"point":3,"male_lines":["C'est le nouveau programme de comptabilité pour mon travail. Tu pourrais m'aider ?"],"female_lines":["Oui, passe ce soir vers dix-huit heures, je te montrerai comment faire."]},{"point":4,"male_lines":["Génial, merci beaucoup ! Je t'apporte une pizza pour le dîner alors."],"female_lines":["Parfait, c'est une bonne affaire pour moi ! À ce soir."]}]},{"id":22,"section":"D","theme":"Giving advice","question":"Quel conseil donne la femme ?","options":[{"id":"A","text":"Prendre des vacances","image_prompt":null},{"id":"B","text":"Changer de travail","image_prompt":null},{"id":"C","text":"Voir un médecin","image_prompt":null},{"id":"D","text":"Faire du sport","image_prompt":null}],"correct":0,"transcript_fr":"Tu devrais vraiment prendre quelques jours de repos, tu as l'air épuisé. - Tu as raison, je vais demander des vacances.","transcript_en":"You should really take a few days off, you look exhausted. - You're right, I'll ask for vacation.","points":[{"point":1,"male_lines":["Je ne sais pas quoi faire, je me sens complètement vidé en ce moment."],"female_lines":["Ça fait combien de temps que tu n'as pas pris de vacances ?"]},{"point":2,"male_lines":["Au moins un an, j'ai eu tellement de travail que je n'ai pas eu le temps de souffler."],"female_lines":["Tu devrais vraiment prendre quelques jours de repos, tu as l'air épuisé."]},{"point":3,"male_lines":["Tu as raison, mais j'ai peur de laisser tomber mon équipe."],"female_lines":["Ton équipe comprendra. La santé passe avant tout, tu le sais bien."]},{"point":4,"male_lines":["C'est vrai. Je vais parler à mon patron demain pour demander une semaine de congé."],"female_lines":["C'est une excellente décision. Repose-toi bien, tu en as besoin."]}]},{"id":23,"section":"E","theme":"Radio interview - Author","question":"Quel est le sujet principal de l'entretien ?","options":[{"id":"A","text":"Un nouveau roman","image_prompt":null},{"id":"B","text":"Une biographie","image_prompt":null},{"id":"C","text":"Un livre de cuisine","image_prompt":null},{"id":"D","text":"Un guide touristique","image_prompt":null}],"correct":0,"transcript_fr":"Aujourd'hui nous recevons l'auteure québécoise Marie-Claire Blais pour son nouveau roman 'Les Jours de l'ombre'. Marie-Claire, pouvez-vous nous parler de l'inspiration derrière ce livre ? - Ce roman explore les relations familiales complexes dans le Québec des années soixante. J'ai voulu capturer l'atmosphère de cette époque tout en abordant des thèmes universels comme le pardon et la réconciliation.","transcript_en":"Today we welcome Quebec author Marie-Claire Blais for her new novel 'The Days of Shadow'. Marie-Claire, can you tell us about the inspiration behind this book? - This novel explores complex family relationships in 1960s Quebec. I wanted to capture the atmosphere of that era while addressing universal themes like forgiveness and reconciliation.","points":[{"point":1,"male_lines":["Bonjour à tous et bienvenue sur Radio-Canada. Aujourd'hui nous recevons l'auteure québécoise Marie-Claire Blais."],"female_lines":["Bonjour et merci de m'inviter sur vos ondes."]},{"point":2,"male_lines":["Votre nouveau roman 'Les Jours de l'ombre' vient de paraître. De quoi parle-t-il exactement ?"],"female_lines":["Ce roman explore les relations familiales complexes dans le Québec des années soixante."]},{"point":3,"male_lines":["Qu'est-ce qui vous a inspiré à écrire sur cette période précise ?"],"female_lines":["J'ai voulu capturer l'atmosphère de cette époque tout en abordant des thèmes universels comme le pardon."]},{"point":4,"male_lines":["Pensez-vous que ce livre résonnera avec les lecteurs d'aujourd'hui ?"],"female_lines":["Absolument, car les questions familiales et le besoin de réconciliation sont intemporels."]}]},{"id":24,"section":"E","theme":"Radio interview - Scientist","question":"Quelle découverte présente le scientifique ?","options":[{"id":"A","text":"Une nouvelle espèce animale","image_prompt":null},{"id":"B","text":"Un médicament contre le cancer","image_prompt":null},{"id":"C","text":"Une énergie renouvelable","image_prompt":null},{"id":"D","text":"Une technique de conservation","image_prompt":null}],"correct":2,"transcript_fr":"Nous avons développé une nouvelle méthode pour stocker l'énergie solaire plus efficacement. - Cette découverte pourrait-elle vraiment changer notre façon de consommer l'énergie ? - Absolument. Notre technologie permet de stocker l'énergie pendant plusieurs semaines, ce qui résout le problème de l'intermittence des énergies renouvelables.","transcript_en":"We have developed a new method to store solar energy more efficiently. - Could this discovery really change the way we consume energy? - Absolutely. Our technology allows storing energy for several weeks, which solves the problem of intermittency of renewable energies.","points":[{"point":1,"male_lines":["Docteur Lefebvre, vous annoncez une découverte majeure aujourd'hui. De quoi s'agit-il ?"],"female_lines":["Nous avons développé une nouvelle méthode pour stocker l'énergie solaire plus efficacement."]},{"point":2,"male_lines":["Cette découverte pourrait-elle vraiment changer notre façon de consommer l'énergie ?"],"female_lines":["Absolument. Notre technologie permet de stocker l'énergie pendant plusieurs semaines."]},{"point":3,"male_lines":["Quel est l'avantage par rapport aux batteries actuelles ?"],"female_lines":["Nous résolvons le problème de l'intermittence des énergies renouvelables à moindre coût."]},{"point":4,"male_lines":["Quand cette technologie sera-t-elle disponible pour le grand public ?"],"female_lines":["Nous espérons un déploiement commercial d'ici deux à trois ans."]}]},{"id":25,"section":"E","theme":"Radio interview - Musician","question":"Quel style musical le musicien présente ?","options":[{"id":"A","text":"Le jazz","image_prompt":null},{"id":"B","text":"La musique traditionnelle québécoise","image_prompt":null},{"id":"C","text":"Le hip-hop","image_prompt":null},{"id":"D","text":"La musique classique","image_prompt":null}],"correct":1,"transcript_fr":"Mon nouvel album revisite les chansons à répondre traditionnelles avec des instruments modernes. - Pourquoi avoir choisi de mélanger tradition et modernité ? - Je voulais montrer que notre patrimoine musical est vivant et peut parler aux jeunes générations d'aujourd'hui.","transcript_en":"My new album revisits traditional call-and-response songs with modern instruments. - Why did you choose to mix tradition and modernity? - I wanted to show that our musical heritage is alive and can speak to today's younger generations.","points":[{"point":1,"male_lines":["Bienvenue sur nos ondes, Monsieur Gagnon. Votre nouvel album sort demain."],"female_lines":["Merci, c'est un projet qui me tient particulièrement à cœur."]},{"point":2,"male_lines":["Quel style musical peut-on attendre de cet album ?"],"female_lines":["Mon nouvel album revisite les chansons à répondre traditionnelles avec des instruments modernes."]},{"point":3,"male_lines":["Pourquoi avoir choisi de mélanger tradition et modernité ?"],"female_lines":["Je voulais montrer que notre patrimoine musical est vivant et peut parler aux jeunes générations."]},{"point":4,"male_lines":["Avez-vous des concerts prévus pour promouvoir cet album ?"],"female_lines":["Oui, une tournée au Québec et en Acadie commence le mois prochain."]}]},{"id":26,"section":"E","theme":"Radio interview - Chef","question":"Quelle est la spécialité du chef ?","options":[{"id":"A","text":"La pâtisserie","image_prompt":null},{"id":"B","text":"La cuisine végétarienne","image_prompt":null},{"id":"C","text":"Les fruits de mer","image_prompt":null},{"id":"D","text":"La cuisine du terroir","image_prompt":null}],"correct":3,"transcript_fr":"Je cuisine exclusivement avec des produits locaux du Québec, des fromages d'ici, des légumes de nos fermes. - Est-ce que cette approche limite votre créativité ? - Au contraire, les contraintes stimulent la créativité. Travailler avec des ingrédients de saison me force à renouveler constamment mon menu.","transcript_en":"I cook exclusively with local Quebec products, cheeses from here, vegetables from our farms. - Does this approach limit your creativity? - On the contrary, constraints stimulate creativity. Working with seasonal ingredients forces me to constantly renew my menu.","points":[{"point":1,"male_lines":["Chef Tremblay, votre restaurant est réputé dans tout Montréal. Quelle est votre philosophie culinaire ?"],"female_lines":["Je cuisine exclusivement avec des produits locaux du Québec, des fromages d'ici, des légumes de nos fermes."]},{"point":2,"male_lines":["Est-ce que cette approche limitée aux produits locaux ne restreint pas votre créativité ?"],"female_lines":["Au contraire, les contraintes stimulent la créativité."]},{"point":3,"male_lines":["Pouvez-vous nous donner un exemple de plat qui représente bien votre cuisine ?"],"female_lines":["Mon célèbre tourtière revisitée avec du canard confit et des légumes racines rôtis."]},{"point":4,"male_lines":["Quels sont vos projets pour les prochains mois ?"],"female_lines":["J'ouvre un second restaurant à Québec qui suivra la même philosophie du terroir."]}]},{"id":27,"section":"F","theme":"Urban planning","question":"Quel est l'avis de la femme sur le projet ?","options":[{"id":"A","text":"Elle est totalement contre","image_prompt":null},{"id":"B","text":"Elle est favorable avec des réserves","image_prompt":null},{"id":"C","text":"Elle n'a pas d'opinion","image_prompt":null},{"id":"D","text":"Elle est totalement pour","image_prompt":null}],"correct":1,"transcript_fr":"Je comprends qu'on ait besoin de plus de logements, mais je m'inquiète pour les espaces verts. - Mais le projet prévoit un grand parc au centre ! - Oui, mais sera-t-il vraiment accessible à tous ? J'aimerais voir les plans détaillés avant de me prononcer définitivement.","transcript_en":"I understand that we need more housing, but I'm worried about green spaces. - But the project includes a large park in the center! - Yes, but will it really be accessible to everyone? I would like to see the detailed plans before making a final decision.","points":[{"point":1,"male_lines":["Qu'est-ce que tu penses du nouveau projet d'aménagement dans notre quartier ?"],"female_lines":["Je comprends qu'on ait besoin de plus de logements, mais je m'inquiète pour les espaces verts."]},{"point":2,"male_lines":["Mais le projet prévoit un grand parc au centre du nouveau développement !"],"female_lines":["Oui, mais sera-t-il vraiment accessible à tous les résidents ou juste aux plus riches ?"]},{"point":3,"male_lines":["Tu penses vraiment qu'il y aura une ségrégation dans l'accès au parc ?"],"female_lines":["Je ne sais pas, c'est ce que je crains. J'aimerais voir les plans détaillés avant de me prononcer définitivement."]},{"point":4,"male_lines":["On pourrait assister à la prochaine réunion du conseil de quartier ensemble."],"female_lines":["Bonne idée, j'aurai sûrement des questions à poser aux urbanistes."]}]},{"id":28,"section":"F","theme":"Education reform","question":"Quelle est la position de l'homme ?","options":[{"id":"A","text":"Il soutient la réforme complètement","image_prompt":null},{"id":"B","text":"Il est opposé à la réforme","image_prompt":null},{"id":"C","text":"Il propose des modifications","image_prompt":null},{"id":"D","text":"Il s'abstient de commenter","image_prompt":null}],"correct":2,"transcript_fr":"La réforme est nécessaire, mais elle va trop vite. On devrait la mettre en place progressivement sur trois ans. - Mais les enfants souffrent du système actuel ! - Je sais, mais si on impose tout d'un coup, les enseignants ne seront pas prêts et ça sera pire pour les élèves.","transcript_en":"The reform is necessary, but it's going too fast. We should implement it gradually over three years. - But children are suffering from the current system! - I know, but if we impose everything at once, teachers won't be ready and it will be worse for students.","points":[{"point":1,"male_lines":["Que penses-tu de la nouvelle réforme du système éducatif annoncée par le ministre ?"],"female_lines":["Je pense que des changements sont nécessaires, mais je m'inquiète de la rapidité de mise en œuvre."]},{"point":2,"male_lines":["La réforme est nécessaire, mais elle va trop vite. On devrait la mettre en place progressivement sur trois ans."],"female_lines":["Mais les enfants souffrent déjà du système actuel, ils ne peuvent pas attendre trois ans de plus !"]},{"point":3,"male_lines":["Je sais, mais si on impose tout d'un coup, les enseignants ne seront pas prêts et ça sera pire pour les élèves."],"female_lines":["Tu as peut-être raison sur le rythme, mais certaines mesures ne peuvent plus attendre."]},{"point":4,"male_lines":["Je propose qu'on commence par les matières essentielles cette année et qu'on ajoute le reste progressivement."],"female_lines":["C'est un compromis acceptable. Il faut juste s'assurer que le gouvernement respecte ce calendrier."]}]},{"id":29,"section":"F","theme":"Teleworking","question":"Quel argument utilise la femme ?","options":[{"id":"A","text":"Le télétravail augmente la productivité","image_prompt":null},{"id":"B","text":"Le télétravail réduit la pollution","image_prompt":null},{"id":"C","text":"Le télétravail améliore l'équilibre vie-travail","image_prompt":null},{"id":"D","text":"Le télétravail coûte moins cher","image_prompt":null}],"correct":2,"transcript_fr":"Depuis que je télétravaille, je passe plus de temps avec mes enfants et je suis moins stressée. - Mais tu ne manques pas de voir tes collègues ? - Si, mais la qualité de vie est tellement meilleure. Je peux organiser mon travail autour de ma famille au lieu de l'inverse.","transcript_en":"Since I've been teleworking, I spend more time with my children and I'm less stressed. - But don't you miss seeing your colleagues? - Yes, but the quality of life is so much better. I can organize my work around my family instead of the other way around.","points":[{"point":1,"male_lines":["Tu travailles encore à la maison trois jours par semaine ? Tu ne trouves pas ça isolant ?"],"female_lines":["Depuis que je télétravaille, je passe plus de temps avec mes enfants et je suis moins stressée."]},{"point":2,"male_lines":["Mais tu ne manques pas de voir tes collègues et de discuter autour du café ?"],"female_lines":["Si, bien sûr, mais la qualité de vie est tellement meilleure que ça compense largement."]},{"point":3,"male_lines":["Comment fais-tu pour séparer ta vie professionnelle de ta vie personnelle ?"],"female_lines":["Je peux organiser mon travail autour de ma famille au lieu de l'inverse. C'est libérateur."]},{"point":4,"male_lines":["Je comprends. Peut-être que je devrais négocier un jour de télétravail par semaine aussi."],"female_lines":["Je te le recommande vivement. Ça change vraiment la qualité de vie quotidienne."]}]},{"id":30,"section":"F","theme":"Immigration policy","question":"Sur quoi les deux personnes sont-elles d'accord ?","options":[{"id":"A","text":"Sur la nécessité de contrôler l'immigration","image_prompt":null},{"id":"B","text":"Sur l'accueil de plus d'immigrants","image_prompt":null},{"id":"C","text":"Sur l'importance de l'intégration","image_prompt":null},{"id":"D","text":"Sur la fermeture des frontières","image_prompt":null}],"correct":2,"transcript_fr":"Je pense qu'on devrait accueillir plus d'immigrants, mais il faut mieux les intégrer. - Je suis d'accord sur l'intégration, même si je pense qu'on doit d'abord prendre soin de nos chômeurs. - Exactement, l'important c'est qu'ils apprennent le français et trouvent un emploi rapidement.","transcript_en":"I think we should welcome more immigrants, but we need to integrate them better. - I agree on integration, even if I think we should first take care of our unemployed. - Exactly, the important thing is that they learn French and find a job quickly.","points":[{"point":1,"male_lines":["Quelle est ta position sur la politique d'immigration actuelle du Canada ?"],"female_lines":["Je pense qu'on devrait accueillir plus d'immigrants, mais il faut absolument mieux les intégrer."]},{"point":2,"male_lines":["Je suis d'accord sur l'intégration, même si je pense qu'on doit d'abord prendre soin de nos chômeurs actuels."],"female_lines":["Je comprends ton point de vue, mais l'immigration peut aussi créer des emplois."]},{"point":3,"male_lines":["Exactement, l'important c'est qu'ils apprennent le français et trouvent un emploi rapidement."],"female_lines":["Oui, les cours de francisation et les programmes d'emploi doivent être renforcés."]},{"point":4,"male_lines":["On est d'accord sur l'essentiel alors : l'intégration réussie est la clé."],"female_lines":["Tout à fait. Un immigrant bien intégré enrichit toute la société."]}]},{"id":31,"section":"G","theme":"Climate change debate","question":"Quelle est la thèse principale de l'argumentation ?","options":[{"id":"A","text":"Le changement climatique est une invention","image_prompt":null},{"id":"B","text":"L'action individuelle est insuffisante","image_prompt":null},{"id":"C","text":"Les technologies vertes sont la solution","image_prompt":null},{"id":"D","text":"Il est trop tard pour agir","image_prompt":null}],"correct":1,"transcript_fr":"Bien que recycler et utiliser des sacs réutilisables soient des gestes louables, ils ne suffisent pas face à l'urgence climatique. Seule une transformation systémique de nos économies peut sauver notre planète. Les gouvernements doivent imposer des réglementations strictes aux grandes entreprises pollueuses.","transcript_en":"Although recycling and using reusable bags are commendable gestures, they are not enough in the face of the climate emergency. Only a systemic transformation of our economies can save our planet. Governments must impose strict regulations on large polluting companies.","points":[{"point":1,"male_lines":["On nous répète sans cesse de trier nos déchets et d'éteindre les lumières."],"female_lines":["Oui, et bien que recycler et utiliser des sacs réutilisables soient des gestes louables, ils ne suffisent pas face à l'urgence climatique."]},{"point":2,"male_lines":["Tu veux dire que nos efforts personnels sont vains ?"],"female_lines":["Pas vains, mais insuffisants. Seule une transformation systémique de nos économies peut sauver notre planète."]},{"point":3,"male_lines":["Mais les entreprises prétendent qu'elles investissent dans le vert."],"female_lines":["Le greenwashing ne suffit plus. Les gouvernements doivent imposer des réglementations strictes aux grandes entreprises pollueuses."]},{"point":4,"male_lines":["Penses-tu que les politiciens auront le courage de faire ces changements ?"],"female_lines":["Ils n'ont pas le choix. La pression citoyenne doit devenir incontournable pour les forcer à agir."]},{"point":5,"male_lines":["Et l'individualisme de notre société ne rend-il pas cette mobilisation difficile ?"],"female_lines":["C'est vrai, mais les mouvements de jeunesse montrent qu'une prise de conscience collective est possible."]},{"point":6,"male_lines":["Quelles mesures concrètes proposerais-tu pour commencer ?"],"female_lines":["Interdiction immédiate des plastiques à usage unique et taxe carbone progressive mais inévitable."]},{"point":7,"male_lines":["Ces mesures risquent de provoquer des réactions violentes de l'industrie."],"female_lines":["L'industrie s'adaptera si les règles sont claires et appliquées uniformément à tous."]},{"point":8,"male_lines":["Et comment convaincre les citoyens de accepter ces changements contraignants ?"],"female_lines":["En montrant que l'alternative est bien pire : un monde invivable pour nos enfants."]},{"point":9,"male_lines":["Tu es pessimiste sur l'avenir ?"],"female_lines":["Réaliste mais pas pessimiste. Nous avons encore les moyens d'agir, mais le temps presse énormément."]},{"point":10,"male_lines":["Je suppose que chaque geste compte, même petit, dans cette lutte collective."],"female_lines":["Exactement. L'important est de ne pas se contenter de gestes symboliques mais d'exiger des changements structurels."]}]},{"id":32,"section":"G","theme":"Digital privacy","question":"Quel danger met en garde l'orateur ?","options":[{"id":"A","text":"La perte de données personnelles","image_prompt":null},{"id":"B","text":"La surveillance de masse","image_prompt":null},{"id":"C","text":"Les cyberattaques","image_prompt":null},{"id":"D","text":"La dépendance aux écrans","image_prompt":null}],"correct":1,"transcript_fr":"Nous vivons dans une société de surveillance où chaque clic, chaque achat, chaque déplacement est enregistré. Les grandes entreprises technologiques connaissent nos habitudes mieux que nous-mêmes. Cette collecte massive de données menace nos libertés fondamentales et notre démocratie.","transcript_en":"We live in a surveillance society where every click, every purchase, every movement is recorded. Big tech companies know our habits better than we do ourselves. This massive data collection threatens our fundamental freedoms and our democracy.","points":[{"point":1,"male_lines":["Nous croyons naïvement que nos données personnelles sont sécurisées."],"female_lines":["Nous vivons en réalité dans une société de surveillance où chaque clic, chaque achat, chaque déplacement est enregistré."]},{"point":2,"male_lines":["Mais les entreprises disent qu'elles protègent notre vie privée."],"female_lines":["Les grandes entreprises technologiques connaissent nos habitudes mieux que nous-mêmes."]},{"point":3,"male_lines":["C'est alarmant quand on y pense. Quelles sont les conséquences ?"],"female_lines":["Cette collecte massive de données menace nos libertés fondamentales et notre démocratie."]},{"point":4,"male_lines":["Comment cela menace-t-il la démocratie concrètement ?"],"female_lines":["Les données peuvent être utilisées pour manipuler l'opinion publique et influencer les élections."]},{"point":5,"male_lines":["Cambridge Analytica a montré que c'était possible."],"female_lines":["Exactement. Et ce n'est qu'un exemple parmi tant d'autres de manipulations invisibles."]},{"point":6,"male_lines":["Que peut faire le citoyen lambda pour se protéger ?"],"female_lines":["Utiliser des moteurs de recherche respectueux de la vie privée et limiter les réseaux sociaux."]},{"point":7,"male_lines":["Mais ces solutions ne sont-elles pas insuffisantes face aux géants du web ?"],"female_lines":["Elles sont nécessaires mais insuffisantes. Il faut une réglementation étatique forte et contraignante."]},{"point":8,"male_lines":["Le RGPD en Europe est un bon début selon toi ?"],"female_lines":["C'est un premier pas, mais les entreprises trouvent toujours des failles pour contourner les règles."]},{"point":9,"male_lines":["Faut-il interdire purement et simplement certaines pratiques ?"],"female_lines":["La vente de données personnelles devrait être illégale et sévèrement punie."]},{"point":10,"male_lines":["J'espère que la prise de conscience grandira avant qu'il ne soit trop tard."],"female_lines":["Nous devons agir maintenant car une fois nos données volées, il est impossible de les récupérer."]}]},{"id":33,"section":"G","theme":"Universal basic income","question":"Quel argument principal est présenté ?","options":[{"id":"A","text":"Le revenu universel éliminerait la pauvreté","image_prompt":null},{"id":"B","text":"Le revenu universel remplacerait tous les autres services sociaux","image_prompt":null},{"id":"C","text":"Le revenu universel encouragerait la paresse","image_prompt":null},{"id":"D","text":"Le revenu universel s'adapterait à l'automatisation","image_prompt":null}],"correct":3,"transcript_fr":"Avec l'automatisation croissante, des millions d'emplois disparaîtront. Le revenu universel de base n'est pas une option de luxe mais une nécessité économique. Il permettrait à chacun de vivre décemment tout en s'adaptant aux nouvelles réalités du marché du travail.","transcript_en":"With increasing automation, millions of jobs will disappear. Universal basic income is not a luxury option but an economic necessity. It would allow everyone to live decently while adapting to the new realities of the job market.","points":[{"point":1,"male_lines":["Le débat sur le revenu universel refait surface régulièrement."],"female_lines":["Avec l'automatisation croissante, des millions d'emplois disparaîtront dans les prochaines décennies."]},{"point":2,"male_lines":["Tu crois vraiment que les robots vont remplacer autant de travailleurs ?"],"female_lines":["Le revenu universel de base n'est pas une option de luxe mais une nécessité économique inévitable."]},{"point":3,"male_lines":["Mais comment financer un tel programme ?"],"female_lines":["Il permettrait à chacun de vivre décemment tout en s'adaptant aux nouvelles réalités du marché du travail."]},{"point":4,"male_lines":["Les impôts augmenteraient massivement pour les entreprises ?"],"female_lines":["Une taxe sur les robots et l'intelligence artificielle pourrait financer en partie ce revenu."]},{"point":5,"male_lines":["Et les gens ne risquent-ils pas de ne plus vouloir travailler ?"],"female_lines":["Les études montrent que la majorité des gens veulent continuer à travailler même avec un revenu de base."]},{"point":6,"male_lines":["Quels emplois resteraient selon toi ?"],"female_lines":["Les métiers créatifs, sociaux et ceux nécessitant l'empathie humaine resteront indispensables."]},{"point":7,"male_lines":["Le pilote en Ontario a été annulé malheureusement."],"female_lines":["Oui, mais les résultats préliminaires montraient une amélioration de la santé mentale des participants."]},{"point":8,"male_lines":["Comment convaincre les politiciens conservateurs de ce projet ?"],"female_lines":["En montrant que cela réduit les coûts administratifs des programmes sociaux actuels complexes."]},{"point":9,"male_lines":["Le coût total serait astronomique pour l'État."],"female_lines":["Moins cher que les conséquences sociales du chômage de masse : criminalité, santé, désespoir."]},{"point":10,"male_lines":["C'est une révolution sociale majeure que tu proposes."],"female_lines":["Une révolution nécessaire pour éviter l'effondrement de notre modèle économique actuel."]}]},{"id":34,"section":"G","theme":"Bilingualism in Canada","question":"Quelle vision du bilinguisme est défendue ?","options":[{"id":"A","text":"L'anglais doit être la seule langue officielle","image_prompt":null},{"id":"B","text":"Le bilinguisme est un atout économique","image_prompt":null},{"id":"C","text":"Le français doit être protégé coûte que coûte","image_prompt":null},{"id":"D","text":"Le bilinguisme est une contrainte inutile","image_prompt":null}],"correct":1,"transcript_fr":"Le bilinguisme canadien n'est pas une faiblesse mais une force économique majeure. Dans un monde globalisé, parler deux langues officielles ouvre des marchés internationaux. Les entreprises bilingues ont un avantage compétitif indéniable sur la scène mondiale.","transcript_en":"Canadian bilingualism is not a weakness but a major economic strength. In a globalized world, speaking two official languages opens international markets. Bilingual companies have an undeniable competitive advantage on the world stage.","points":[{"point":1,"male_lines":["Certains politiciens voient le bilinguisme comme un frein économique."],"female_lines":["Le bilinguisme canadien n'est pas une faiblesse mais une force économique majeure."]},{"point":2,"male_lines":["Comment le fait de parler deux langues peut-il être un avantage économique ?"],"female_lines":["Dans un monde globalisé, parler deux langues officielles ouvre des marchés internationaux."]},{"point":3,"male_lines":["Les entreprises canadiennes en tirent-elles vraiment parti ?"],"female_lines":["Les entreprises bilingues ont un avantage compétitif indéniable sur la scène mondiale."]},{"point":4,"male_lines":["Donner l'exemple avec le français aide à faire des affaires en Afrique ?"],"female_lines":["Exactement. L'Afrique francophone est un marché en pleine croissance pour nos exportations."]},{"point":5,"male_lines":["Et pour les relations commerciales avec les États-Unis ?"],"female_lines":["Le bilinguisme facilite les échanges avec la Louisiane et les communautés francophones américaines."]},{"point":6,"male_lines":["Certains jeunes québécois ne voient pas l'utilité du français."],"female_lines":["Ils ignorent que le bilinguisme augmente significativement leur salaire potentiel."]},{"point":7,"male_lines":["Les statistiques le confirment-elles ?"],"female_lines":["Les bilingues gagnent en moyenne dix pour cent de plus que les unilingues au Canada."]},{"point":8,"male_lines":["Mais l'immersion française coûte cher aux contribuables."],"female_lines":["C'est un investissement qui rapporte dix fois son coût en retombées économiques futures."]},{"point":9,"male_lines":["Comment renforcer cette vision économique du bilinguisme ?"],"female_lines":["En formant des ambassadeurs économiques bilingues qui rayonnent à l'international."]},{"point":10,"male_lines":["Le bilinguisme est donc un atout à préserver coûte que coûte."],"female_lines":["C'est notre identité distinctive et notre passeport pour le commerce mondial."]}]},{"id":35,"section":"G","theme":"Mental health at work","question":"Quelle solution est proposée pour améliorer la santé mentale ?","options":[{"id":"A","text":"Augmenter les salaires","image_prompt":null},{"id":"B","text":"Réduire le temps de travail","image_prompt":null},{"id":"C","text":"Former les managers","image_prompt":null},{"id":"D","text":"Embaucher des psychologues","image_prompt":null}],"correct":2,"transcript_fr":"Le burn-out touche un travailleur sur trois au Canada. La solution ne réside pas seulement en congés supplémentaires mais dans la formation des managers à détecter les signes de détresse. Un manager bien formé peut prévenir la crise avant qu'elle n'éclate.","transcript_en":"Burnout affects one in three workers in Canada. The solution lies not only in additional leave but in training managers to detect signs of distress. A well-trained manager can prevent the crisis before it breaks out.","points":[{"point":1,"male_lines":["Les problèmes de santé mentale explosent dans nos entreprises."],"female_lines":["Le burn-out touche désormais un travailleur sur trois au Canada."]},{"point":2,"male_lines":["Les entreprises offrent pourtant des programmes de bien-être."],"female_lines":["La solution ne réside pas seulement en congés supplémentaires mais dans la formation des managers."]},{"point":3,"male_lines":["Former les managers à quoi exactement ?"],"female_lines":["À détecter les signes de détresse chez leurs employés avant qu'ils ne deviennent critiques."]},{"point":4,"male_lines":["Un manager n'est pas psychologue pourtant."],"female_lines":["Un manager bien formé peut prévenir la crise avant qu'elle n'éclate sans faire de diagnostic médical."]},{"point":5,"male_lines":["Quels signes doit-il apprendre à reconnaître ?"],"female_lines":["L'isolement soudain, la baisse de performance, l'irritabilité et les absences répétées."]},{"point":6,"male_lines":["Et une fois ces signes repérés, que fait le manager ?"],"female_lines":["Il ouvre un dialogue bienveillant et oriente vers les ressources d'aide disponibles."]},{"point":7,"male_lines":["Les managers ont-ils le temps pour cela dans leur emploi du temps chargé ?"],"female_lines":["Ils doivent comprendre que préserver la santé mentale de l'équipe est leur priorité première."]},{"point":8,"male_lines":["Cette formation devrait-elle être obligatoire ?"],"female_lines":["Absolument, comme la formation sur la sécurité au travail est obligatoire."]},{"point":9,"male_lines":["Quel retour sur investissement pour l'entreprise ?"],"female_lines":["Un employé en bonne santé mentale est trois fois plus productif qu'un employé en souffrance."]},{"point":10,"male_lines":["C'est un changement de culture profond que tu proposes."],"female_lines":["Un changement nécessaire pour que le travail ne tue plus lentement nos concitoyens."]}]},{"id":36,"section":"H","theme":"Philosophy of technology","question":"Quelle critique de la technologie est présentée ?","options":[{"id":"A","text":"Elle rend les gens plus intelligents","image_prompt":null},{"id":"B","text":"Elle modifie notre rapport au réel","image_prompt":null},{"id":"C","text":"Elle résout tous les problèmes humains","image_prompt":null},{"id":"D","text":"Elle est neutre moralement","image_prompt":null}],"correct":1,"transcript_fr":"La technologie n'est pas un simple outil neutre mais un médium qui reshape notre perception de la réalité. Quand nous regardons le monde à travers nos écrans, nous ne voyons plus le monde tel qu'il est mais tel que les algorithmes le présentent. Cette médiation technologique altère profondément notre expérience du réel.","transcript_en":"Technology is not a simple neutral tool but a medium that reshapes our perception of reality. When we look at the world through our screens, we no longer see the world as it is but as algorithms present it. This technological mediation profoundly alters our experience of reality.","points":[{"point":1,"male_lines":["Nous considérons la technologie comme un outil neutre au service de l'humanité."],"female_lines":["La technologie n'est pas un simple outil neutre mais un médium qui reshape notre perception de la réalité."]},{"point":2,"male_lines":["Que signifie reshape dans ce contexte philosophique ?"],"female_lines":["Quand nous regardons le monde à travers nos écrans, nous ne voyons plus le monde tel qu'il est."]},{"point":3,"male_lines":["Nous voyons le monde filtré par nos appareils ?"],"female_lines":["Nous voyons le monde tel que les algorithmes le présentent, sélectionné et formaté."]},{"point":4,"male_lines":["Cette médiation est-elle nécessairement négative ?"],"female_lines":["Cette médiation technologique altère profondément notre expérience du réel et notre rapport à l'autre."]},{"point":5,"male_lines":["Peut-on échapper à cette médiation dans le monde moderne ?"],"female_lines":["Il est presque impossible, mais nous pouvons développer une conscience critique de ces filtres."]},{"point":6,"male_lines":["Comment développer cette conscience critique ?"],"female_lines":["En comprenant comment fonctionnent les algorithmes et en diversifiant nos sources d'information."]},{"point":7,"male_lines":["La technologie crée-t-elle une réalité parallèle ?"],"female_lines":["Elle crée des bulles de réalité où chacun vit dans son propre monde informationnel."]},{"point":8,"male_lines":["Cette fragmentation menace-t-elle la cohésion sociale ?"],"female_lines":["Elle rend le dialogue démocratique difficile car nous ne partageons plus les mêmes faits."]},{"point":9,"male_lines":["Faut-il renoncer à ces technologies pour retrouver le réel ?"],"female_lines":["Non, mais il faut les utiliser en connaissance de cause et garder du temps sans écran."]},{"point":10,"male_lines":["La philosophie peut-elle nous aider à naviguer dans ce monde médiatisé ?"],"female_lines":["Elle est indispensable pour questionner notre rapport à la vérité et à l'authenticité technologique."]}]},{"id":37,"section":"H","theme":"Post-colonial studies","question":"Quel concept central est discuté ?","options":[{"id":"A","text":"L'assimilation culturelle","image_prompt":null},{"id":"B","text":"L'hybridité culturelle","image_prompt":null},{"id":"C","text":"L'indépendance politique","image_prompt":null},{"id":"D","text":"La mondialisation économique","image_prompt":null}],"correct":1,"transcript_fr":"L'hybridité culturelle défie la notion pure et authentique d'identité. Dans les sociétés post-coloniales, les individus ne sont ni totalement colonisés ni totalement traditionnels. Ils habitent un espace entre-deux où se mêlent influences diverses créant de nouvelles formes culturelles uniques.","transcript_en":"Cultural hybridity challenges the pure and authentic notion of identity. In post-colonial societies, individuals are neither totally colonized nor totally traditional. They inhabit an in-between space where diverse influences mix, creating unique new cultural forms.","points":[{"point":1,"male_lines":["Les études post-coloniales interrogent la notion d'identité culturelle fixe."],"female_lines":["L'hybridité culturelle défie la notion pure et authentique d'identité prétendument originelle."]},{"point":2,"male_lines":["Que signifie exactement hybridité dans ce contexte ?"],"female_lines":["Dans les sociétés post-coloniales, les individus ne sont ni totalement colonisés ni totalement traditionnels."]},{"point":3,"male_lines":["Ils se situent entre deux mondes ?"],"female_lines":["Ils habitent un espace entre-deux où se mêlent influences diverses créant de nouvelles formes culturelles uniques."]},{"point":4,"male_lines":["C'est une position confortable ou inconfortable ?"],"female_lines":["C'est souvent une position de tension mais aussi de créativité culturelle extraordinaire."]},{"point":5,"male_lines":["Donner un exemple concret d'hybridité culturelle."],"female_lines":["La littérature maghrébine d'expression française mêle traditions orales arabes et formes romanesques européennes."]},{"point":6,"male_lines":["L'hybridité est-elle une forme de résistance ?"],"female_lines":["C'est une résistance subtile contre les identités imposées aussi bien coloniales que nationalistes rigides."]},{"point":7,"male_lines":["Les puristes critiquent-ils cette hybridité ?"],"female_lines":["Ils l'accusent d'être une trahison de l'authenticité, mais l'authenticité pure est un mythe."]},{"point":8,"male_lines":["Comment cette théorie s'applique-t-elle au Québec ?"],"female_lines":["Le Québec est lui-même un espace hybride entre héritage français, influence anglo-saxonne et créativité propre."]},{"point":9,"male_lines":["L'hybridité menace-t-elle la survie du français au Québec ?"],"female_lines":["Non, elle enrichit le français québécois d'emprunts créatifs tout en gardant une identité forte."]},{"point":10,"male_lines":["C'est une vision optimiste de la rencontre des cultures."],"female_lines":["C'est reconnaître que toute culture est en constante transformation et dialogue avec l'autre."]}]},{"id":38,"section":"H","theme":"Cognitive biases","question":"Quel biais cognitif est illustré ?","options":[{"id":"A","text":"L'effet de halo","image_prompt":null},{"id":"B","text":"Le biais de confirmation","image_prompt":null},{"id":"C","text":"L'ancrage cognitif","image_prompt":null},{"id":"D","text":"La dissonance cognitive","image_prompt":null}],"correct":1,"transcript_fr":"Nous avons tendance à chercher uniquement les informations qui confirment nos croyances préexistantes. Quand nous lisons l'actualité, nous retenons ce qui valide notre vision du monde et ignorons ce qui la contredit. Ce mécanisme crée des chambres d'écho intellectuelles dangereuses.","transcript_en":"We tend to seek only information that confirms our pre-existing beliefs. When we read the news, we retain what validates our worldview and ignore what contradicts it. This mechanism creates dangerous intellectual echo chambers.","points":[{"point":1,"male_lines":["Nous croyons raisonner objectivement mais nos cerveaux nous trompent."],"female_lines":["Nous avons tendance à chercher uniquement les informations qui confirment nos croyances préexistantes."]},{"point":2,"male_lines":["C'est le fameux biais de confirmation ?"],"female_lines":["Quand nous lisons l'actualité, nous retenons ce qui valide notre vision du monde et ignorons ce qui la contredit."]},{"point":3,"male_lines":["Nous devenons aveugles aux faits contradictoires ?"],"female_lines":["Ce mécanisme crée des chambres d'écho intellectuelles dangereuses pour la démocratie."]},{"point":4,"male_lines":["Comment ce biais se manifeste-t-il concrètement ?"],"female_lines":["Un partisan politique ne lira que les journaux qui confortent son camp et méprisera les autres."]},{"point":5,"male_lines":["Peut-on surmonter ce biais naturel ?"],"female_lines":["C'est difficile car il est inconscient, mais la méthode scientifique aide à s'en protéger."]},{"point":6,"male_lines":["La méthode scientifique comment exactement ?"],"female_lines":["En testant activement nos hypothèses plutôt que de chercher des preuves à leur appui."]},{"point":7,"male_lines":["Les réseaux sociaux aggravent-ils ce phénomène ?"],"female_lines":["Ils créent des bulles de filtre où l'algorithme ne montre que ce qui correspond à nos préférences."]},{"point":8,"male_lines":["Que peut faire l'individu pour échapper à ces bulles ?"],"female_lines":["S'efforcer de lire des sources d'opposition et de comprendre les arguments adverses sérieusement."]},{"point":9,"male_lines":["C'est un exercice intellectuel pénible pourtant."],"female_lines":["C'est pénible car cela remet en question notre confort cognitif et notre identité."]},{"point":10,"male_lines":["Sans cet effort, nous sommes condamnés à l'ignorance volontaire."],"female_lines":["Exactement. La pensée critique exige de se confronter activement à ce qui nous dérange."]}]},{"id":39,"section":"H","theme":"Ethics of artificial intelligence","question":"Quel dilemme éthique est soulevé ?","options":[{"id":"A","text":"Le droit des robots","image_prompt":null},{"id":"B","text":"La responsabilité algorithmique","image_prompt":null},{"id":"C","text":"Le coût de développement","image_prompt":null},{"id":"D","text":"La vitesse de calcul","image_prompt":null}],"correct":1,"transcript_fr":"Quand une intelligence artificielle prend une décision discriminatoire, qui est responsable ? Le programmeur, l'entreprise, ou l'algorithme lui-même ? Nous devons établir un cadre éthique clair avant que ces systèmes ne prennent des décisions vitales pour nos vies.","transcript_en":"When an artificial intelligence makes a discriminatory decision, who is responsible? The programmer, the company, or the algorithm itself? We must establish a clear ethical framework before these systems make vital decisions for our lives.","points":[{"point":1,"male_lines":["Les intelligences artificielles prennent de plus en plus de décisions à notre place."],"female_lines":["Quand une intelligence artificielle prend une décision discriminatoire, qui est responsable ?"]},{"point":2,"male_lines":["C'est une question éthique fondamentale. Quelles sont les réponses possibles ?"],"female_lines":["Le programmeur, l'entreprise, ou l'algorithme lui-même ? Chaque option pose problème."]},{"point":3,"male_lines":["Pourquoi l'algorithme lui-même ne peut-il pas être responsable ?"],"female_lines":["Car il n'a pas de conscience morale ni d'intention, il ne fait qu'appliquer des règles statistiques."]},{"point":4,"male_lines":["Et le programmeur qui a écrit le code ?"],"female_lines":["Il ne peut pas prévoir tous les biais que l'IA développera en apprenant sur des données historiques."]},{"point":5,"male_lines":["Reste l'entreprise qui déploie l'IA ?"],"female_lines":["C'est souvent le choix par défaut, mais cela freine l'innovation par peur des procès."]},{"point":6,"male_lines":["Quelle solution proposes-tu pour sortir de cette impasse ?"],"female_lines":["Nous devons établir un cadre éthique clair avant que ces systèmes ne prennent des décisions vitales pour nos vies."]},{"point":7,"male_lines":["Ce cadre devrait-il être imposé par les États ou l'industrie ?"],"female_lines":["Par les États avec la collaboration de l'industrie pour que les règles soient réalistes et applicables."]},{"point":8,"male_lines":["Comment auditer l'éthique d'un algorithme complexe ?"],"female_lines":["Il faut des comités d'éthique indépendants avec accès au code source et aux données d'entraînement."]},{"point":9,"male_lines":["Cela ne ralentira-t-il pas le progrès technologique ?"],"female_lines":["Un progrès sans éthique n'est pas un progrès mais une menace pour l'humanité."]},{"point":10,"male_lines":["L'Europe semble prendre la tête avec son AI Act."],"female_lines":["Oui, mais le Canada doit aussi légiférer rapidement pour ne pas importer des technologies éthiquement dangereuses."]}]},{"id":40,"section":"H","theme":"Phenomenology of space","question":"Quelle conception de l'espace est présentée ?","options":[{"id":"A","text":"L'espace comme contenant vide","image_prompt":null},{"id":"B","text":"L'espace comme expérience vécue","image_prompt":null},{"id":"C","text":"L'espace comme propriété mathématique","image_prompt":null},{"id":"D","text":"L'espace comme ressource économique","image_prompt":null}],"correct":1,"transcript_fr":"L'espace n'est pas une entité abstraite et mathématique mais une réalité que nous vivons corporellement. Notre maison n'est pas un ensemble de coordonnées géométriques mais un lieu chargé de souvenirs et d'affects. La phénoménologie nous apprend à habiter l'espace plutôt qu'à simplement l'occuper.","transcript_en":"Space is not an abstract mathematical entity but a reality we live bodily. Our home is not a set of geometric coordinates but a place full of memories and affects. Phenomenology teaches us to inhabit space rather than simply occupy it.","points":[{"point":1,"male_lines":["Nous concevons l'espace comme un contenant vide où nous plaçons des objets."],"female_lines":["L'espace n'est pas une entité abstraite et mathématique mais une réalité que nous vivons corporellement."]},{"point":2,"male_lines":["Comment l'espace devient-il une expérience vécue ?"],"female_lines":["Notre maison n'est pas un ensemble de coordonnées géométriques mais un lieu chargé de souvenirs et d'affects."]},{"point":3,"male_lines":["L'espace a donc une dimension émotionnelle ?"],"female_lines":["La phénoménologie nous apprend à habiter l'espace plutôt qu'à simplement l'occuper physiquement."]},{"point":4,"male_lines":["Quelle différence entre habiter et occuper ?"],"female_lines":["Occuper c'est être là physiquement, habiter c'est y être chez soi, y être en sécurité existentielle."]},{"point":5,"male_lines":["Cette conception s'applique-t-elle aussi aux espaces publics ?"],"female_lines":["Un parc peut être un lieu de promenade anonyme ou un lieu de rencontre et de communauté vécue."]},{"point":6,"male_lines":["L'urbanisme moderne a-t-il oublié cette dimension ?"],"female_lines":["L'urbanisme fonctionnel a privilégié la circulation sur l'habitabilité et créé des espaces anonymes."]},{"point":7,"male_lines":["Comment créer des espaces qui favorisent l'habiter ?"],"female_lines":["En pensant l'échelle humaine, les rencontres possibles, et la qualité sensorielle des matériaux."]},{"point":8,"male_lines":["Le confinement a-t-il changé notre rapport à l'espace domestique ?"],"female_lines":["Il a révélé l'importance vitale de l'espace habitable versus l'espace fonctionnel minimaliste."]},{"point":9,"male_lines":["Le bureau à domicile illustre cette tension ?"],"female_lines":["Exactement. Le bureau envahit l'espace du foyer et trouble la distinction entre travail et intimité."]},{"point":10,"male_lines":["Il faut donc repenser nos habitats pour préserver cette qualité d'habiter."],"female_lines":["Oui, car habiter dignement est fondamental pour la santé mentale et le sentiment d'appartenance au monde."]}]}]`);export{e as default};
